    with pytest.raises(ZeroDivisionError):
        Sum_of_Inverse_Divisors(0, 12)

def test_boundary_N_negative_one():
    assert Sum_of_Inverse_Divisors(-1, 12) == -12.0

def test_boundary_N_one():
    assert Sum_of_Inverse_Divisors(1, 12) == 12.0

def test_boundary_N_large():
    assert Sum_of_Inverse_Divisors(1000000, 12) == 0.0

def test_boundary_Sum_zero():
    assert Sum_of_Inverse_Divisors(6, 0) == 0.0

def test_boundary_Sum_negative_one():
    assert Sum_of_Inverse_Divisors(6, -1) == -0.17

def test_boundary_Sum_one():
    assert Sum_of_Inverse_Divisors(6, 1) == 0.17

def test_boundary_Sum_large():
    assert Sum_of_Inverse_Divisors(6, 1000000) == 166666.67

