import pytest
from solution import raw_heap

def test_boundary_rawheap_empty():
    assert raw_heap([]) == []

def test_boundary_rawheap_single():
    assert raw_heap([1]) == [1]

def test_boundary_rawheap_duplicates():
    assert raw_heap([1, 1, 1]) == [1, 1, 1]

def test_boundary_rawheap_with_zero():
    assert raw_heap([0]) == [0]

def test_boundary_rawheap_with_negative():
    assert raw_heap([-1]) == [-1]
